const item = $input.first();

if (!item || !item.json || !item.json.output) {
  throw new Error("A chave 'output' não foi encontrada no JSON de entrada.");
}

const textoEntrada = item.json.output;

let textoProcessado = textoEntrada.replace(/\n/g, " ");

// Substituições fonéticas para TTS pt-BR
textoProcessado = textoProcessado
  .replace(/\bn8n\b/gi, 'nêitiên')
  .replace(/\bMCP\b/g, 'ême cê pê')
  .replace(/\bRAG\b/g, 'réguê')
  .replace(/\bLLM\b/g, 'éle éle ême')
  .replace(/\bAPI\b/g, 'a pê i')
  .replace(/\bTTS\b/g, 'tê tê ésse')
  .replace(/\bIA\b/g, 'inteligência artificial')
  .replace(/https?:\/\/\S+/g, '')
  .replace(/#\w+/g, '');

// Remove emojis
textoProcessado = textoProcessado.replace(
  /[\u{1F600}-\u{1F64F}]|[\u{1F300}-\u{1F5FF}]|[\u{1F680}-\u{1F6FF}]|[\u{1F700}-\u{1F77F}]|[\u{1F780}-\u{1F7FF}]|[\u{1F800}-\u{1F8FF}]|[\u{1F900}-\u{1F9FF}]|[\u{1FA00}-\u{1FA6F}]|[\u{1FA70}-\u{1FAFF}]|[\u{2600}-\u{26FF}]|[\u{2700}-\u{27BF}]|[\u{FE00}-\u{FE0F}]|[\u{1F1E0}-\u{1F1FF}]/gu,
  ""
);

// Remove caracteres especiais mantendo pontuação útil para TTS
textoProcessado = textoProcessado.replace(/[^a-zA-Z0-9À-ÿ\s.,!?;:\-()]/g, "");

// Normaliza espaços
textoProcessado = textoProcessado.replace(/\s+/g, " ").trim();

return {
  textoOriginal: textoEntrada,
  textoSemQuebrasNemEmojisNemEspeciais: textoProcessado,
};

const items = $input.all();

if (items.length === 0 || !items[0].json?.summary) {
  return [{ json: { text: "Agenda limpa hoje, senhor. Dia livre para conquistar o mundo." } }];
}

const lines = items.map(e => {
  const s = e.json.start?.dateTime || e.json.start?.date || '';
  const d = new Date(s);
  const h = d.getHours().toString().padStart(2, '0');
  const m = d.getMinutes().toString().padStart(2, '0');
  const time = s.includes('T') ? h + ':' + m : 'dia todo';
  return time + ' \u2014 ' + e.json.summary;
});

return [{ json: { text: "*Agenda de hoje:*\n\n" + lines.join("\n") } }];

const items = $input.all();

if (items.length === 0) {
  return [{ json: { text: "Inbox limpo, senhor. Milagres acontecem." } }];
}

const lines = items.slice(0, 5).map(e => {
  const fromRaw = e.json.from || e.json.sender || 'Desconhecido';
  const from = fromRaw.toString().replace(/<[^>]+>/g, '').trim().substring(0, 25);
  const subject = (e.json.subject || '(sem assunto)').substring(0, 45);
  return '*' + from + '* \u2014 ' + subject;
});

return [{ json: { text: "*\u00DAltimos emails:*\n\n" + lines.join("\n") } }];
